INSERT INTO `chat_messages` VALUES (1,1,33,NULL,'Welcome to the team! 👋','text',0,0,NULL,NULL,'2026-03-04 17:58:29','2026-03-05 15:58:29',NULL),(2,1,32,NULL,'Has anyone seen the latest project updates?','text',0,0,NULL,NULL,'2026-03-05 06:58:29','2026-03-05 15:58:29',NULL),(3,1,34,NULL,'Great work on the presentation today!','text',0,0,NULL,NULL,'2026-03-02 15:58:29','2026-03-05 15:58:29',NULL),(4,1,29,NULL,'Don\'t forget about the meeting at 3 PM','text',0,0,NULL,NULL,'2026-03-03 15:58:29','2026-03-05 15:58:29',NULL),(5,1,25,NULL,'Happy Friday everyone! 🎉','text',0,0,NULL,NULL,'2026-03-03 20:58:29','2026-03-05 15:58:29',NULL),(6,1,30,NULL,'The new HR360 system is looking great!','text',0,0,NULL,NULL,'2026-03-03 04:58:29','2026-03-05 15:58:29',NULL),(7,1,33,NULL,'Thanks everyone for the warm welcome','text',0,0,NULL,NULL,'2026-03-04 02:58:29','2026-03-05 15:58:29',NULL),(8,1,27,NULL,'Looking forward to working with you all','text',0,0,NULL,NULL,'2026-03-05 06:58:29','2026-03-05 15:58:29',NULL),(9,2,26,NULL,'I\'ve uploaded the documents to the shared drive','text',0,0,NULL,NULL,'2026-03-03 18:58:29','2026-03-05 15:58:29',NULL),(10,2,27,NULL,'Can someone review my pull request?','text',0,0,NULL,NULL,'2026-03-04 01:58:29','2026-03-05 15:58:29',NULL),(11,2,28,NULL,'The new feature is looking great','text',0,0,NULL,NULL,'2026-03-04 00:58:29','2026-03-05 15:58:29',NULL),(12,2,31,NULL,'Thanks for your help with that bug','text',0,0,NULL,NULL,'2026-03-05 13:58:29','2026-03-05 15:58:29',NULL),(13,2,29,NULL,'Let\'s schedule a sync-up call','text',0,0,NULL,NULL,'2026-03-05 09:58:29','2026-03-05 15:58:29',NULL),(14,2,32,NULL,'Code review meeting at 2 PM today','text',0,0,NULL,NULL,'2026-03-02 18:58:29','2026-03-05 15:58:29',NULL),(15,2,26,NULL,'Deployed the latest changes to staging','text',0,0,NULL,NULL,'2026-03-04 20:58:29','2026-03-05 15:58:29',NULL),(16,2,33,NULL,'Anyone available for pair programming?','text',0,0,NULL,NULL,'2026-03-02 17:58:29','2026-03-05 15:58:29',NULL),(17,3,25,NULL,'New employee onboarding starts Monday','text',0,0,NULL,NULL,'2026-03-03 05:58:29','2026-03-05 15:58:29',NULL),(18,3,23,NULL,'Please submit your timesheets by Friday','text',0,0,NULL,NULL,'2026-03-05 07:58:29','2026-03-05 15:58:29',NULL),(19,3,23,NULL,'Benefits enrollment deadline is next week','text',0,0,NULL,NULL,'2026-03-04 03:58:29','2026-03-05 15:58:29',NULL),(20,3,25,NULL,'Team building event scheduled for next month','text',0,0,NULL,NULL,'2026-03-03 05:58:29','2026-03-05 15:58:29',NULL),(21,3,23,NULL,'Performance reviews are due by end of quarter','text',0,0,NULL,NULL,'2026-03-04 19:58:29','2026-03-05 15:58:29',NULL),(22,4,28,NULL,'Anyone up for lunch? 🍕','text',0,0,NULL,NULL,'2026-03-05 14:58:29','2026-03-05 15:58:29',NULL),(23,4,26,NULL,'Great weather today! ☀️','text',0,0,NULL,NULL,'2026-03-03 17:58:29','2026-03-05 15:58:29',NULL),(24,4,31,NULL,'Coffee break anyone? ☕','text',0,0,NULL,NULL,'2026-03-04 11:58:29','2026-03-05 15:58:29',NULL),(25,4,31,NULL,'Happy birthday to our team member! 🎂','text',0,0,NULL,NULL,'2026-03-02 18:58:29','2026-03-05 15:58:29',NULL),(26,4,33,NULL,'Weekend plans anyone?','text',0,0,NULL,NULL,'2026-03-03 02:58:29','2026-03-05 15:58:29',NULL),(27,4,33,NULL,'Check out this cool article I found','text',0,0,NULL,NULL,'2026-03-05 04:58:29','2026-03-05 15:58:29',NULL),(28,5,25,NULL,'<p>hello guy</p>','text',0,0,NULL,NULL,'2026-03-07 05:40:00','2026-03-07 05:40:00',NULL),(29,6,35,NULL,'<p>Hello please can you sent me the book now😀</p>','text',0,0,NULL,NULL,'2026-03-13 09:21:22','2026-03-13 09:21:22',NULL),(34,5,27,NULL,'<p>sup</p>','text',0,0,NULL,NULL,'2026-03-14 23:40:01','2026-03-14 23:40:01',NULL),(35,5,27,NULL,'<p>so let us meet tomorrow</p>','text',0,0,NULL,NULL,'2026-03-15 00:35:52','2026-03-15 00:35:52',NULL),(36,7,35,NULL,'<p>hello sir, please</p>','text',0,0,NULL,NULL,'2026-03-15 10:53:52','2026-03-15 10:53:52',NULL),(37,7,35,NULL,'<p>please let us talk when you are available</p>','text',0,0,NULL,NULL,'2026-03-15 