DROP TABLE IF EXISTS `memos`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `memos` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `sender_id` bigint(20) unsigned NOT NULL,
  `organization_id` bigint(20) unsigned NOT NULL DEFAULT 1,
  `thread_id` bigint(20) unsigned DEFAULT NULL,
  `parent_memo_id` bigint(20) unsigned DEFAULT NULL,
  `subject` varchar(255) NOT NULL,
  `body` longtext NOT NULL,
  `body_plain` text DEFAULT NULL,
  `priority` enum('low','normal','high','urgent') NOT NULL DEFAULT 'normal',
  `status` enum('draft','scheduled','sent','failed') NOT NULL DEFAULT 'draft',
  `type` enum('memo','reply','forward') NOT NULL DEFAULT 'memo',
  `scheduled_at` timestamp NULL DEFAULT NULL,
  `sent_at` timestamp NULL DEFAULT NULL,
  `requires_read_receipt` tinyint(1) NOT NULL DEFAULT 0,
  `is_confidential` tinyint(1) NOT NULL DEFAULT 0,
  `metadata` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`metadata`)),
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `memos_parent_memo_id_foreign` (`parent_memo_id`),
  KEY `memos_sender_id_created_at_index` (`sender_id`,`created_at`),
  KEY `memos_organization_id_status_index` (`organization_id`,`status`),
  KEY `memos_thread_id_created_at_index` (`thread_id`,`created_at`),
  KEY `memos_scheduled_at_index` (`scheduled_at`),
  FULLTEXT KEY `memos_subject_body_plain_fulltext` (`subject`,`body_plain`),
  CONSTRAINT `memos_parent_memo_id_foreign` FOREIGN KEY (`parent_memo_id`) REFERENCES `memos` (`id`) ON DELETE SET NULL,
  CONSTRAINT `memos_sender_id_foreign` FOREIGN KEY (`sender_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `memos_thread_id_foreign` FOREIGN KEY (`thread_id`) REFERENCES `memo_threads` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=22 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

