INSERT INTO `memos` VALUES (10,23,1,7,NULL,'Re: Project Alpha - Architecture Review','<p>I\'ve gone through the proposal and it looks solid. My only concern is the timeline - can we discuss this further?</p>','I\'ve gone through the proposal and it looks solid. My only concern is the timeline - can we discuss this further?','normal','sent','reply',NULL,'2026-03-03 16:02:29',0,0,NULL,'2026-03-03 16:02:29','2026-03-03 16:02:29',NULL),(16,25,1,11,NULL,'Testing the Memo','Want to let you know the real state of the&nbsp;','Want to let you know the real state of the&nbsp;','normal','sent','memo',NULL,'2026-03-04 23:58:37',0,0,NULL,'2026-03-04 23:58:37','2026-03-05 09:03:39','2026-03-05 09:03:39'),(17,25,1,12,NULL,'Deployment  Status','<p data-start=\"76\" data-end=\"104\"><strong data-start=\"76\" data-end=\"102\">&nbsp;</strong><span data-start=\"76\" data-end=\"102\"><b>Friendly message 😊</b></span></p>\n<blockquote data-start=\"105\" data-end=\"222\">\n<p data-start=\"107\" data-end=\"222\">Hey! Just checking in to see how your day is going. Hope everything is moving in the right direction for you today.</p>\n</blockquote>\n<p data-start=\"224\" data-end=\"256\"><strong data-start=\"224\" data-end=\"254\">2. Motivational message 🚀</strong></p>\n<blockquote data-start=\"257\" data-end=\"360\">\n<p data-start=\"259\" data-end=\"360\">Keep pushing forward. Even the smallest progress today is building the success you’ll enjoy tomorrow.</p>\n</blockquote>\n<p data-start=\"362\" data-end=\"394\"><strong data-start=\"362\" data-end=\"392\">3. Professional message 💼</strong></p>\n<blockquote data-start=\"395\" data-end=\"599\">\n<p data-start=\"397\" data-end=\"599\">Good day. I hope this message finds you well. I wanted to briefly check in and see if there are any updates regarding the project. Please let me know if you need any additional information from my side.</p>\n</blockquote>\n<p data-start=\"601\" data-end=\"634\"><strong data-start=\"601\" data-end=\"632\">4. Inspirational message 🌟</strong></p>\n<blockquote data-start=\"635\" data-end=\"760\">\n<p data-start=\"637\" data-end=\"760\">Success rarely comes from comfort zones. Every step you take outside your limits is shaping a stronger version of yourself.</p></blockquote>','&nbsp;Friendly message 😊\n\nHey! Just checking in to see how your day is going. Hope everything is moving in the right direction for you today.\n\n2. Motivational message 🚀\n\nKeep pushing forward. Even the smallest progress today is building the success you’ll enjoy tomorrow.\n\n3. Professional message 💼\n\nGood day. I hope this message finds you well. I wanted to briefly check in and see if there are any updates regarding the project. Please let me know if you need any additional information from my side.\n\n4. Inspirational message 🌟\n\nSuccess rarely comes from comfort zones. Every step you take outside your limits is shaping a stronger version of yourself.','urgent','sent','memo',NULL,'2026-03-05 09:06:27',0,0,NULL,'2026-03-05 09:06:27','2026-03-05 10:10:05','2026-03-05 10:10:05'),(18,25,1,13,NULL,'Friendly Messaging','<p data-start=\"76\" data-end=\"104\" style=\"--tw-scale-x: 1; --tw-scale-y: 1; --tw-pan-x: ; --tw-pan-y: ; --tw-pinch-zoom: ; --tw-scroll-snap-strictness: proximity; --tw-gradient-from-position: ; --tw-gradient-via-position: ; --tw-gradient-to-position: ; --tw-ordinal: ; --tw-slashed-zero: ; --tw-numeric-figure: ; --tw-numeric-spacing: ; --tw-numeric-fraction: ; --tw-ring-inset: ; --tw-ring-offset-width: 0px; --tw-ring-offset-color: #fff; --tw-ring-color: rgb(59 130 246 / 0.5); --tw-ring-offset-shadow: 0 0 #0000; --tw-ring-shadow: 0 0 #0000; --tw-shadow: 0 0 #0000; --tw-shadow-colored: 0 0 #0000; --tw-blur: ; --tw-brightness: ; --tw-contrast: ; --tw-grayscale: ; --tw-hue-rotate: ; --tw-invert: ; --tw-saturate: ; --tw-sepia: ; --tw-drop-shadow: ; --tw-backdrop-blur: ; --tw-backdrop-brightness: ; --tw-backdrop-contrast: ; --tw-backdrop-grayscale: ; --tw-backdrop-hue-rotate: ; --tw-backdro