INSERT INTO `performance_configs` VALUES (8,4,'Sales Weekly Performance','Weekly performance tracking for sales team','[{\"id\":\"sales_metrics\",\"title\":\"Sales Metrics\",\"description\":\"Track your sales performance\",\"required\":true,\"fields\":[{\"id\":\"revenue\",\"label\":\"Revenue Generated\",\"type\":\"currency\",\"required\":true,\"scoreable\":true,\"target\":500000,\"weight\":40,\"placeholder\":\"Enter revenue amount\"},{\"id\":\"new_clients\",\"label\":\"New Clients Acquired\",\"type\":\"number\",\"required\":true,\"scoreable\":true,\"target\":5,\"weight\":30,\"min\":0},{\"id\":\"meetings\",\"label\":\"Client Meetings\",\"type\":\"number\",\"required\":true,\"scoreable\":true,\"target\":10,\"weight\":20,\"min\":0}]},{\"id\":\"quality_metrics\",\"title\":\"Quality & Satisfaction\",\"required\":false,\"fields\":[{\"id\":\"client_satisfaction\",\"label\":\"Client Satisfaction Rating\",\"type\":\"rating\",\"required\":true,\"scoreable\":true,\"weight\":10,\"max\":5}]},{\"id\":\"notes\",\"title\":\"Additional Notes\",\"required\":false,\"fields\":[{\"id\":\"achievements\",\"label\":\"Key Achievements\",\"type\":\"textarea\",\"required\":false,\"placeholder\":\"Describe your key achievements this week...\",\"rows\":4},{\"id\":\"challenges\",\"label\":\"Challenges Faced\",\"type\":\"textarea\",\"required\":false,\"placeholder\":\"Describe any challenges you faced...\",\"rows\":4}]}]','{\"method\":\"weighted\",\"ratingThresholds\":[{\"min\":90,\"max\":100,\"label\":\"Exceptional\",\"color\":\"text-green-600\",\"bgColor\":\"bg-green-50\",\"borderColor\":\"border-green-300\"},{\"min\":80,\"max\":89,\"label\":\"Excellent\",\"color\":\"text-blue-600\",\"bgColor\":\"bg-blue-50\",\"borderColor\":\"border-blue-300\"},{\"min\":70,\"max\":79,\"label\":\"Very Good\",\"color\":\"text-cyan-600\",\"bgColor\":\"bg-cyan-50\",\"borderColor\":\"border-cyan-300\"},{\"min\":60,\"max\":69,\"label\":\"Good\",\"color\":\"text-yellow-600\",\"bgColor\":\"bg-yellow-50\",\"borderColor